fn run_sequence(
    agent: &ureq::Agent,
    url: &str,
    warmup: usize,
    iterations: usize,
    start_token: u32,
    start_position: usize,
    request_offset: usize,
    ffn_mode: Option<&str>,
    guard_admit_weather_cells: Option<&str>,
    guard_speculate_weather_cells: Option<&str>,
    guard_deny_weather_cells: Option<&str>,
    predictive_min_gate_up_skip_blocks: Option<&str>,
    guard_min_logit_margin: Option<&str>,
    guard_high_confidence_logit_margin: Option<&str>,
    guard_rms_delta3_threshold: Option<&str>,
) -> Result<Vec<Sample>, String> {
    let mut token = start_token;
    let mut position = start_position;
    for i in 0..warmup {
        let sample = request_decode_next(
            agent,
            url,
            token,
            position,
            request_offset + i,
            ffn_mode,
            guard_admit_weather_cells,
            guard_speculate_weather_cells,
            guard_deny_weather_cells,
            predictive_min_gate_up_skip_blocks,
            guard_min_logit_margin,
            guard_high_confidence_logit_margin,
            guard_rms_delta3_threshold,
        )?;
        token = sample.token_id;
        position += 1;
    }

    let mut samples = Vec::with_capacity(iterations);
    for i in 0..iterations {
        let sample = request_decode_next(
            agent,
            url,
            token,
            position,
            request_offset + warmup + i,
            ffn_mode,
            guard_admit_weather_cells,
            guard_speculate_weather_cells,
            guard_deny_weather_cells,
            predictive_min_gate_up_skip_blocks,
            guard_min_logit_margin,
            guard_high_confidence_logit_margin,
            guard_rms_delta3_threshold,
        )?;
        token = sample.token_id;
        position += 1;
        samples.push(sample);
    }
    Ok(samples)
}

fn run_interleaved_compare(
    agent: &ureq::Agent,
    url: &str,
    warmup: usize,
    iterations: usize,
    start_token: u32,
    start_position: usize,
    request_offset: usize,
    baseline_mode: &str,
    candidate_mode: &str,
    guard_admit_weather_cells: Option<&str>,
    guard_speculate_weather_cells: Option<&str>,
    guard_deny_weather_cells: Option<&str>,
    predictive_min_gate_up_skip_blocks: Option<&str>,
    guard_min_logit_margin: Option<&str>,
    guard_high_confidence_logit_margin: Option<&str>,
    guard_rms_delta3_threshold: Option<&str>,
) -> Result<(Vec<Sample>, Vec<Sample>), String> {
    let mut baseline_token = start_token;
    let mut candidate_token = start_token;
    let mut baseline_position = start_position;
    let mut candidate_position = start_position;
    let mut request_index = request_offset;
    let mut baseline_samples = Vec::with_capacity(iterations);
    let mut candidate_samples = Vec::with_capacity(iterations);

    for step in 0..(warmup + iterations) {
        let measured = step >= warmup;
        let baseline_first = step % 2 == 0;

        if baseline_first {
            let baseline = request_decode_next(
                agent,
                url,
                baseline_token,
                baseline_position,
                request_index,
                Some(baseline_mode),
                guard_admit_weather_cells,
                guard_speculate_weather_cells,
                guard_deny_weather_cells,
                predictive_min_gate_up_skip_blocks,
                guard_min_logit_margin,
                guard_high_confidence_logit_margin,
                guard_rms_delta3_threshold,
            )?;
            request_index += 1;
            baseline_token = baseline.token_id;
            baseline_position += 1;
            if measured {
                baseline_samples.push(baseline);
            }

            let candidate = request_decode_next(
                agent,
                url,
                candidate_token,
                candidate_position,
                request_index,
                Some(candidate_mode),
                guard_admit_weather_cells,
                guard_speculate_weather_cells,
                guard_deny_weather_cells,
                predictive_min_gate_up_skip_blocks,
                guard_min_logit_margin,
                guard_high_confidence_logit_margin,
                guard_rms_delta3_threshold,
            )?;
            request_index += 1;
            candidate_token = candidate.token_id;
            candidate_position += 1;
            if measured {
                candidate_samples.push(candidate);
            }
        } else {
            let candidate = request_decode_next(
                agent,
                url,
                candidate_token,
                candidate_position,
                request_index,
                Some(candidate_mode),
                guard_admit_weather_cells,
                guard_speculate_weather_cells,
                guard_deny_weather_cells,
                predictive_min_gate_up_skip_blocks,
                guard_min_logit_margin,
                guard_high_confidence_logit_margin,
                guard_rms_delta3_threshold,
            )?;
            request_index += 1;
            candidate_token = candidate.token_id;
            candidate_position += 1;
            if measured {
                candidate_samples.push(candidate);
            }

            let baseline = request_decode_next(
                agent,
                url,
                baseline_token,
                baseline_position,
                request_index,
                Some(baseline_mode),
                guard_admit_weather_cells,
                guard_speculate_weather_cells,
                guard_deny_weather_cells,
                predictive_min_gate_up_skip_blocks,
                guard_min_logit_margin,
                guard_high_confidence_logit_margin,
                guard_rms_delta3_threshold,
            )?;
            request_index += 1;
            baseline_token = baseline.token_id;
            baseline_position += 1;
            if measured {
                baseline_samples.push(baseline);
            }
        }
    }

    Ok((baseline_samples, candidate_samples))
}

fn run_interleaved_probe(
    agent: &ureq::Agent,
    url: &str,
    warmup: usize,
    iterations: usize,
    start_token: u32,
    start_position: usize,
    request_offset: usize,
    baseline_mode: &str,
    candidate_mode: &str,
    probe_mode: &str,
    guard_admit_weather_cells: Option<&str>,
    guard_speculate_weather_cells: Option<&str>,
    guard_deny_weather_cells: Option<&str>,
    predictive_min_gate_up_skip_blocks: Option<&str>,
    guard_min_logit_margin: Option<&str>,
    guard_high_confidence_logit_margin: Option<&str>,
    guard_rms_delta3_threshold: Option<&str>,
) -> Result<(Vec<Sample>, Vec<Sample>, Vec<Sample>), String> {
    let mut tokens = [start_token, start_token, start_token];
    let mut positions = [start_position, start_position, start_position];
    let modes = [baseline_mode, candidate_mode, probe_mode];
    let mut request_index = request_offset;
    let mut baseline_samples = Vec::with_capacity(iterations);
    let mut candidate_samples = Vec::with_capacity(iterations);
    let mut probe_samples = Vec::with_capacity(iterations);
    let orders = [
        [0usize, 1usize, 2usize],
        [1usize, 2usize, 0usize],
        [2usize, 0usize, 1usize],
    ];

    for step in 0..(warmup + iterations) {
        let measured = step >= warmup;
        for stream_index in orders[step % orders.len()] {
            let sample = request_decode_next(
                agent,
                url,
                tokens[stream_index],
                positions[stream_index],
                request_index,
                Some(modes[stream_index]),
                guard_admit_weather_cells,
                guard_speculate_weather_cells,
                guard_deny_weather_cells,
                predictive_min_gate_up_skip_blocks,
                guard_min_logit_margin,
                guard_high_confidence_logit_margin,
                guard_rms_delta3_threshold,
            )?;
            request_index += 1;
            tokens[stream_index] = sample.token_id;
            positions[stream_index] += 1;
            if measured {
                match stream_index {
                    0 => baseline_samples.push(sample),
                    1 => candidate_samples.push(sample),
                    2 => probe_samples.push(sample),
                    _ => unreachable!("static stream index"),
                }
            }
        }
    }

    Ok((baseline_samples, candidate_samples, probe_samples))
}

fn run_weather_grid_probe(
    agent: &ureq::Agent,
    url: &str,
    label: &str,
    warmup: usize,
    iterations: usize,
    starts: Vec<WeatherGridStartSpec>,
    baseline_mode: &str,
    candidate_mode: &str,
    probe_mode: &str,
    gate: BenchmarkGate,
    policy_min_samples: usize,
    policy_min_replicates: usize,
    policy_min_replicate_samples: usize,
    policy_max_conservative_rate: f64,
    policy_min_p50_speedup: f64,
    policy_min_p90_speedup: f64,
    policy_min_ffn_speedup: f64,
    guard_admit_weather_cells: Option<&str>,
    guard_speculate_weather_cells: Option<&str>,
    guard_deny_weather_cells: Option<&str>,
    predictive_min_gate_up_skip_blocks: Option<&str>,
    guard_min_logit_margin: Option<&str>,
    guard_high_confidence_logit_margin: Option<&str>,
    guard_rms_delta3_threshold: Option<&str>,
) -> Result<WeatherGridReport, String> {
    let mut baseline_samples = Vec::with_capacity(starts.len() * iterations);
    let mut candidate_samples = Vec::with_capacity(starts.len() * iterations);
    let mut probe_samples = Vec::with_capacity(starts.len() * iterations);
    let mut replicate_weather_probes = Vec::with_capacity(starts.len());
    let mut request_offset = 0usize;
    let requests_per_start = (warmup + iterations).saturating_mul(3);

    for start in &starts {
        let (baseline, candidate, probe) = run_interleaved_probe(
            agent,
            url,
            warmup,
            iterations,
            start.token,
            start.position,
            request_offset,
            baseline_mode,
            candidate_mode,
            probe_mode,
            guard_admit_weather_cells,
            guard_speculate_weather_cells,
            guard_deny_weather_cells,
            predictive_min_gate_up_skip_blocks,
            guard_min_logit_margin,
            guard_high_confidence_logit_margin,
            guard_rms_delta3_threshold,
        )?;
        request_offset = request_offset.saturating_add(requests_per_start);
        let start_baseline = summarize_samples(
            &format!("{label} start {}@{} baseline", start.token, start.position),
            Some(baseline_mode),
            warmup,
            iterations,
            baseline.clone(),
            &[],
        );
        let start_candidate = summarize_samples(
            &format!("{label} start {}@{} candidate", start.token, start.position),
            Some(candidate_mode),
            warmup,
            iterations,
            candidate.clone(),
            &start_baseline.tokens,
        );
        let start_probe = summarize_samples(
            &format!("{label} start {}@{} probe", start.token, start.position),
            Some(probe_mode),
            warmup,
            iterations,
            probe.clone(),
            &start_baseline.tokens,
        );
        replicate_weather_probes.push(weather_probe_summary(
            &start_baseline,
            &start_candidate,
            &start_probe,
        ));
        baseline_samples.extend(baseline);
        candidate_samples.extend(candidate);
        probe_samples.extend(probe);
    }

    let aggregate_iterations = starts.len() * iterations;
    let aggregate_warmup = starts.len() * warmup;
    let baseline = summarize_samples(
        &format!("{label} grid baseline"),
        Some(baseline_mode),
        aggregate_warmup,
        aggregate_iterations,
        baseline_samples,
        &[],
    );
    let candidate = summarize_samples(
        &format!("{label} grid candidate"),
        Some(candidate_mode),
        aggregate_warmup,
        aggregate_iterations,
        candidate_samples,
        &baseline.tokens,
    );
    let probe = summarize_samples(
        &format!("{label} grid probe"),
        Some(probe_mode),
        aggregate_warmup,
        aggregate_iterations,
        probe_samples,
        &baseline.tokens,
    );
    let weather_probe = weather_probe_summary(&baseline, &candidate, &probe);
    let compare = compare_summary(gate, &baseline, &candidate, Some(weather_probe.clone()));
    let replicate_counts = weather_cell_replicate_counts(
        &replicate_weather_probes,
        policy_min_replicate_samples,
        policy_max_conservative_rate,
        policy_min_p50_speedup,
        policy_min_p90_speedup,
        policy_min_ffn_speedup,
    );
    let admissible_cell_candidates = weather_cell_policy_candidates(
        &weather_probe,
        &replicate_counts,
        policy_min_samples,
        policy_max_conservative_rate,
        policy_min_p50_speedup,
        policy_min_p90_speedup,
        policy_min_ffn_speedup,
    );

    Ok(WeatherGridReport {
        label: label.to_string(),
        starts,
        iterations_per_start: iterations,
        warmup_per_start: warmup,
        policy_min_samples,
        policy_min_replicates,
        policy_min_replicate_samples,
        policy_max_conservative_rate,
        policy_min_p50_speedup,
        policy_min_p90_speedup,
        policy_min_ffn_speedup,
        baseline,
        candidate,
        probe,
        compare,
        weather_probe,
        admissible_cell_candidates,
    })
}

fn percentile(sorted: &[u128], pct: f64) -> u128 {
    if sorted.is_empty() {
        return 0;
    }
    let idx = ((sorted.len() as f64 - 1.0) * pct).round() as usize;
    sorted[idx.min(sorted.len() - 1)]
}

fn percentile_u64(sorted: &[u64], pct: f64) -> u64 {
    if sorted.is_empty() {
        return 0;
    }
    let idx = ((sorted.len() as f64 - 1.0) * pct).round() as usize;
    sorted[idx.min(sorted.len() - 1)]
}

fn u128_to_u64(value: u128) -> u64 {
    value.min(u64::MAX as u128) as u64
}

fn mean_u64(samples: &[Sample], f: impl Fn(&Sample) -> u64) -> f64 {
    if samples.is_empty() {
        return 0.0;
    }
    samples.iter().map(f).sum::<u64>() as f64 / samples.len() as f64
}

fn mean_u64_values(values: &[u64]) -> f64 {
    if values.is_empty() {
        return 0.0;
    }
    values.iter().sum::<u64>() as f64 / values.len() as f64
}

fn mean_f64(samples: &[Sample], f: impl Fn(&Sample) -> f64) -> f64 {
    if samples.is_empty() {
        return 0.0;
    }
    samples.iter().map(f).sum::<f64>() / samples.len() as f64
}

fn skip_pct(skipped: u64, total: u64) -> f64 {
    if total == 0 {
        0.0
    } else {
        skipped as f64 * 100.0 / total as f64
    }
}

fn weather_cell_counts(samples: &[Sample]) -> Vec<WeatherCellCount> {
    let mut counts = BTreeMap::<u64, WeatherCellCount>::new();
    for sample in samples {
        let cell = sample.guard_weather_cell;
        if cell == 0 {
            continue;
        }
        let entry = counts.entry(cell).or_insert_with(|| WeatherCellCount {
            cell,
            ..WeatherCellCount::default()
        });
        entry.samples += 1;
        if sample.guard_weather_reject_reasons != 0 {
            entry.weather_rejects += 1;
        }
        if sample.guard_weather_cell_admitted != 0 {
            entry.explicit_admissions += 1;
        }
    }
    counts.into_values().collect()
}

fn weather_cell_position_band(cell: u64) -> u64 {
    (cell / 1000) % 10
}

fn weather_cell_block_band(cell: u64) -> u64 {
    cell % 10
}

fn weather_cell_allows_explicit_admission(cell: u64) -> bool {
    cell != 0 && weather_cell_position_band(cell) != 1 && weather_cell_block_band(cell) != 3
}

fn weather_cell_passes_policy_outcome(
    cell: &WeatherCellOutcome,
    min_samples: usize,
    max_conservative_rate: f64,
    min_p50_speedup: f64,
    min_p90_speedup: f64,
    min_ffn_speedup: f64,
) -> bool {
    if !cell.admission_allowed
        || cell.compared < min_samples
        || cell.raw_probe_divergent_tokens != 0
        || cell.guarded_divergent_tokens != 0
        || cell.missed_raw_divergences != 0
        || cell.p50_speedup < min_p50_speedup
        || cell.p90_speedup < min_p90_speedup
        || cell.ffn_speedup < min_ffn_speedup
    {
        return false;
    }
    let conservative_rate = if cell.compared == 0 {
        0.0
    } else {
        cell.conservative_rejects as f64 / cell.compared as f64
    };
    conservative_rate <= max_conservative_rate
}

fn weather_cell_replicate_counts(
    probes: &[WeatherProbeSummary],
    min_replicate_samples: usize,
    max_conservative_rate: f64,
    min_p50_speedup: f64,
    min_p90_speedup: f64,
    min_ffn_speedup: f64,
) -> BTreeMap<u64, usize> {
    let mut counts = BTreeMap::<u64, usize>::new();
    for probe in probes {
        for cell in &probe.cells {
            if weather_cell_passes_policy_outcome(
                cell,
                min_replicate_samples,
                max_conservative_rate,
                min_p50_speedup,
                min_p90_speedup,
                min_ffn_speedup,
            ) {
                *counts.entry(cell.cell).or_default() += 1;
            }
        }
    }
    counts
}

fn weather_policy_admitted_cell_csv(cells: &[u64]) -> String {
    cells
        .iter()
        .map(|cell| cell.to_string())
        .collect::<Vec<_>>()
        .join(",")
}

fn weather_policy_env_assignment(cells: &[u64]) -> String {
    format!(
        "{WEATHER_POLICY_ENV_VAR}={}",
        weather_policy_admitted_cell_csv(cells)
    )
}

fn guard_reject_reason_label(mask: u64) -> String {
    if mask == 0 {
        return "accepted".to_string();
    }
    let mut labels = Vec::new();
    if mask & 1 != 0 {
        labels.push("position-zero");
    }
    if mask & 2 != 0 {
        labels.push("low-margin");
    }
    if mask & 4 != 0 {
        labels.push("high-blocks");
    }
    if mask & 8 != 0 {
        labels.push("high-drift");
    }
    if labels.is_empty() {
        labels.push("unknown");
    }
    labels.join("|")
}

fn format_margin_trace(values: &[f64]) -> String {
    values
        .iter()
        .map(|value| format!("{value:.6}"))
        .collect::<Vec<_>>()
        .join(",")
}

fn format_weather_cell_counts(cells: &[WeatherCellCount]) -> String {
    cells
        .iter()
        .map(|cell| {
            format!(
                "{}:samples={},rejects={},admissions={}",
                cell.cell, cell.samples, cell.weather_rejects, cell.explicit_admissions
            )
        })
        .collect::<Vec<_>>()
        .join(";")
}

fn format_weather_cell_outcomes(cells: &[WeatherCellOutcome]) -> String {
    cells
        .iter()
        .map(|cell| {
            format!(
                "{}:compared={},admission_allowed={},raw_divergent={},guarded_divergent={},weather_rejects={},caught={},missed={},conservative={},p50_speedup={:.4},p90_speedup={:.4},ffn_speedup={:.4}",
                cell.cell,
                cell.compared,
                cell.admission_allowed,
                cell.raw_probe_divergent_tokens,
                cell.guarded_divergent_tokens,
                cell.weather_rejects,
                cell.caught_raw_divergences,
                cell.missed_raw_divergences,
                cell.conservative_rejects,
                cell.p50_speedup,
                cell.p90_speedup,
                cell.ffn_speedup
            )
        })
        .collect::<Vec<_>>()
        .join(";")
}

fn summarize_samples(
    label: &str,
    mode: Option<&str>,
    warmup: usize,
    iterations: usize,
    samples: Vec<Sample>,
    baseline_tokens: &[u32],
) -> Summary {
    let mut client_us: Vec<u128> = samples.iter().map(|sample| sample.client_us).collect();
    client_us.sort_unstable();
    let p50_us = percentile(&client_us, 0.50);
    let p90_us = percentile(&client_us, 0.90);
    let client_us_trace = samples
        .iter()
        .map(|sample| u128_to_u64(sample.client_us))
        .collect::<Vec<_>>();
    let ffn_total_us_trace = samples.iter().map(Sample::ffn_total_us).collect::<Vec<_>>();
    let tps = if p50_us == 0 {
        0.0
    } else {
        1_000_000.0 / p50_us as f64
    };
    let tokens: Vec<u32> = samples.iter().map(|sample| sample.token_id).collect();
    let divergent_tokens = if baseline_tokens.is_empty() {
        0
    } else {
        baseline_tokens
            .iter()
            .zip(tokens.iter())
            .filter(|(baseline, token)| baseline != token)
            .count()
            + baseline_tokens.len().abs_diff(tokens.len())
    };
    let input_blocks = samples
        .iter()
        .map(|sample| sample.input_blocks)
        .sum::<u64>();
    let input_skipped = samples
        .iter()
        .map(|sample| sample.input_skipped_blocks)
        .sum::<u64>();
    let hidden_blocks = samples
        .iter()
        .map(|sample| sample.hidden_blocks)
        .sum::<u64>();
    let hidden_skipped = samples
        .iter()
        .map(|sample| sample.hidden_skipped_blocks)
        .sum::<u64>();
    let guard_fallbacks = samples
        .iter()
        .map(|sample| sample.guard_fallbacks)
        .sum::<u64>();
    let guard_sieve_pre_rejects = samples
        .iter()
        .map(|sample| sample.guard_sieve_pre_rejects)
        .sum::<u64>();
    let guard_candidate_skipped_blocks = samples
        .iter()
        .map(|sample| sample.guard_candidate_skipped_blocks)
        .sum::<u64>();
    let guard_mirror_reject_reasons = samples.iter().fold(0u64, |mask, sample| {
        mask | sample.guard_mirror_reject_reasons
    });
    let guard_candidate_mirrored_blocks = samples
        .iter()
        .map(|sample| sample.guard_candidate_mirrored_blocks)
        .sum::<u64>();
    let guard_fallback_candidate_logit_margins = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0)
        .map(|sample| sample.guard_candidate_logit_margin)
        .collect::<Vec<_>>();
    let guard_fallback_reject_reasons = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0)
        .map(|sample| sample.guard_mirror_reject_reasons)
        .collect::<Vec<_>>();
    let guard_weather_reject_reasons = samples.iter().fold(0u64, |mask, sample| {
        mask | sample.guard_weather_reject_reasons
    });
    let guard_weather_rejects = samples
        .iter()
        .filter(|sample| sample.guard_weather_reject_reasons != 0)
        .count();
    let guard_weather_fallbacks = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0 && sample.guard_weather_reject_reasons != 0)
        .count() as u64;
    let guard_post_candidate_fallbacks = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0 && sample.guard_mirror_reject_reasons != 0)
        .count() as u64;
    let guard_weather_prior_mirrored_blocks_max = samples
        .iter()
        .map(|sample| sample.guard_weather_prior_mirrored_blocks)
        .max()
        .unwrap_or(0);
    let guard_fallback_weather_reject_reasons = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0)
        .map(|sample| sample.guard_weather_reject_reasons)
        .collect::<Vec<_>>();
    let guard_fallback_pre_residual_rms_tails = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0)
        .map(|sample| sample.pre_residual_rms_tail)
        .collect::<Vec<_>>();
    let guard_fallback_pre_residual_rms_delta_tails = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0)
        .map(|sample| sample.pre_residual_rms_delta_tail)
        .collect::<Vec<_>>();
    let guard_fallback_pre_residual_rms_delta3_tails = samples
        .iter()
        .filter(|sample| sample.guard_fallbacks > 0)
        .map(|sample| sample.pre_residual_rms_delta3_tail)
        .collect::<Vec<_>>();
    let hidden_mirrored_blocks = samples
        .iter()
        .map(|sample| sample.hidden_mirrored_blocks)
        .sum::<u64>();
    let ffn_gate_mean_us = mean_u64(&samples, |sample| sample.ffn_gate_us);
    let ffn_up_mean_us = mean_u64(&samples, |sample| sample.ffn_up_us);
    let ffn_down_mean_us = mean_u64(&samples, |sample| sample.ffn_down_us);
    let matvec_memo_hits = samples
        .iter()
        .map(|sample| sample.matvec_memo_hits)
        .sum::<u64>();
    let matvec_memo_misses = samples
        .iter()
        .map(|sample| sample.matvec_memo_misses)
        .sum::<u64>();
    let matvec_memo_evictions = samples
        .iter()
        .map(|sample| sample.matvec_memo_evictions)
        .sum::<u64>();

    Summary {
        label: label.to_string(),
        mode: mode.map(str::to_string),
        iterations,
        warmup,
        p50_us,
        p90_us,
        client_us_trace,
        tps,
        forward_mean_us: mean_u64(&samples, |sample| sample.forward_us),
        logit_mean_us: mean_u64(&samples, |sample| sample.logit_us),
        attn_norm_mean_us: mean_u64(&samples, |sample| sample.attn_norm_us),
        qkv_fetch_mean_us: mean_u64(&samples, |sample| sample.qkv_fetch_us),
        qkv_matvec_mean_us: mean_u64(&samples, |sample| sample.qkv_matvec_us),
        q_matvec_mean_us: mean_u64(&samples, |sample| sample.q_matvec_us),
        k_matvec_mean_us: mean_u64(&samples, |sample| sample.k_matvec_us),
        v_matvec_mean_us: mean_u64(&samples, |sample| sample.v_matvec_us),
        qkv_bias_mean_us: mean_u64(&samples, |sample| sample.qkv_bias_us),
        qk_norm_mean_us: mean_u64(&samples, |sample| sample.qk_norm_us),
        rope_mean_us: mean_u64(&samples, |sample| sample.rope_us),
        kv_save_mean_us: mean_u64(&samples, |sample| sample.kv_save_us),
        attention_mean_us: mean_u64(&samples, |sample| sample.attention_us),
        o_fetch_mean_us: mean_u64(&samples, |sample| sample.o_fetch_us),
        o_matvec_mean_us: mean_u64(&samples, |sample| sample.o_matvec_us),
        attn_residual_mean_us: mean_u64(&samples, |sample| sample.attn_residual_us),
        pre_ffn_residual_mean_us: mean_u64(&samples, |sample| sample.pre_ffn_residual_us),
        ffn_norm_mean_us: mean_u64(&samples, |sample| sample.ffn_norm_us),
        ffn_cache_mean_us: mean_u64(&samples, |sample| sample.ffn_cache_us),
        ffn_pressure_mean_us: mean_u64(&samples, |sample| sample.ffn_pressure_us),
        ffn_gate_mean_us,
        ffn_up_mean_us,
        ffn_down_mean_us,
        ffn_fetch_mean_us: mean_u64(&samples, |sample| sample.ffn_fetch_us),
        ffn_gate_fetch_mean_us: mean_u64(&samples, |sample| sample.ffn_gate_fetch_us),
        ffn_up_fetch_mean_us: mean_u64(&samples, |sample| sample.ffn_up_fetch_us),
        ffn_down_fetch_mean_us: mean_u64(&samples, |sample| sample.ffn_down_fetch_us),
        ffn_matvec_mean_us: mean_u64(&samples, |sample| sample.ffn_matvec_us),
        ffn_gate_matvec_mean_us: mean_u64(&samples, |sample| sample.ffn_gate_matvec_us),
        ffn_up_matvec_mean_us: mean_u64(&samples, |sample| sample.ffn_up_matvec_us),
        ffn_swiglu_mean_us: mean_u64(&samples, |sample| sample.ffn_swiglu_us),
        ffn_hidden_pressure_mean_us: mean_u64(&samples, |sample| sample.ffn_hidden_pressure_us),
        ffn_down_matvec_mean_us: mean_u64(&samples, |sample| sample.ffn_down_matvec_us),
        ffn_residual_mean_us: mean_u64(&samples, |sample| sample.ffn_residual_us),
        final_norm_mean_us: mean_u64(&samples, |sample| sample.final_norm_us),
        logit_fetch_mean_us: mean_u64(&samples, |sample| sample.logit_fetch_us),
        logit_matvec_mean_us: mean_u64(&samples, |sample| sample.logit_matvec_us),
        matvec_memo_hits,
        matvec_memo_misses,
        matvec_memo_evictions,
        ffn_total_mean_us: ffn_gate_mean_us + ffn_up_mean_us + ffn_down_mean_us,
        ffn_total_us_trace,
        input_skip_pct: skip_pct(input_skipped, input_blocks),
        hidden_skip_pct: skip_pct(hidden_skipped, hidden_blocks),
        guard_fallbacks,
        guard_sieve_pre_rejects,
        guard_candidate_skipped_blocks,
        guard_mirror_reject_reasons,
        guard_candidate_mirrored_blocks,
        guard_candidate_logit_margin_mean: mean_f64(&samples, |sample| {
            sample.guard_candidate_logit_margin
        }),
        guard_fallback_candidate_logit_margins,
        guard_fallback_reject_reasons,
        guard_weather_reject_reasons,
        guard_weather_rejects,
        guard_weather_fallbacks,
        guard_post_candidate_fallbacks,
        guard_weather_prior_mirrored_blocks_max,
        guard_weather_prior_logit_margin_mean: mean_f64(&samples, |sample| {
            sample.guard_weather_prior_logit_margin
        }),
        guard_weather_prior_residual_l2_tail_mean: mean_f64(&samples, |sample| {
            sample.guard_weather_prior_residual_l2_tail
        }),
        guard_weather_prior_residual_rms_tail_mean: mean_f64(&samples, |sample| {
            sample.guard_weather_prior_residual_rms_tail
        }),
        guard_weather_prior_residual_rms_delta_tail_mean: mean_f64(&samples, |sample| {
            sample.guard_weather_prior_residual_rms_delta_tail
        }),
        guard_weather_prior_residual_rms_delta3_tail_mean: mean_f64(&samples, |sample| {
            sample.guard_weather_prior_residual_rms_delta3_tail
        }),
        guard_fallback_weather_reject_reasons,
        guard_weather_reject_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_reject_reasons)
            .collect(),
        guard_weather_cell_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_cell)
            .collect(),
        guard_weather_cell_admission_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_cell_admitted)
            .collect(),
        guard_weather_cell_denial_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_cell_denied)
            .collect(),
        guard_weather_position_band_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_position_band)
            .collect(),
        guard_weather_margin_band_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_margin_band)
            .collect(),
        guard_weather_drift_band_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_drift_band)
            .collect(),
        guard_weather_block_band_trace: samples
            .iter()
            .map(|sample| sample.guard_weather_block_band)
            .collect(),
        guard_weather_cell_counts: weather_cell_counts(&samples),
        guard_fallback_pre_residual_rms_tails,
        guard_fallback_pre_residual_rms_delta_tails,
        guard_fallback_pre_residual_rms_delta3_tails,
        pre_residual_l2_tail_mean: mean_f64(&samples, |sample| sample.pre_residual_l2_tail),
        pre_residual_rms_tail_mean: mean_f64(&samples, |sample| sample.pre_residual_rms_tail),
        pre_residual_rms_delta_tail_mean: mean_f64(&samples, |sample| {
            sample.pre_residual_rms_delta_tail
        }),
        pre_residual_rms_delta3_tail_mean: mean_f64(&samples, |sample| {
            sample.pre_residual_rms_delta3_tail
        }),
        hidden_mirrored_blocks,
        predictive_gate_up_skipped_blocks: samples
            .iter()
            .map(|sample| sample.predictive_gate_up_skipped_blocks)
            .sum(),
        mirror_scale_mean: mean_f64(&samples, |sample| sample.mirror_scale),
        logit_margin_mean: mean_f64(&samples, |sample| sample.logit_margin),
        divergent_tokens,
        tokens,
    }
}

