    #[test]
    fn weather_policy_manifest_signs_admitted_cells() {
        let candidate = WeatherCellPolicyCandidate {
            cell: 2222,
            compared: 16,
            replicates: 1,
            weather_rejects: 2,
            conservative_rejects: 2,
            conservative_rate: 0.125,
            p50_speedup: 1.01,
            p90_speedup: 1.02,
            ffn_speedup: 1.03,
        };
        let report = manifest_report(
            WeatherProbeSummary {
                compared: 16,
                conservative_rejects: 2,
                cells: vec![WeatherCellOutcome {
                    cell: 2222,
                    admission_allowed: true,
                    compared: 16,
                    weather_rejects: 2,
                    conservative_rejects: 2,
                    p50_speedup: 1.01,
                    p90_speedup: 1.02,
                    ffn_speedup: 1.03,
                    ..WeatherCellOutcome::default()
                }],
                ..WeatherProbeSummary::default()
            },
            vec![candidate],
        );

        let manifest = build_weather_policy_manifest(&report).expect("manifest");
        assert_eq!(manifest.payload.kind, WEATHER_POLICY_MANIFEST_KIND);
        assert_eq!(
            manifest.payload.schema_version,
            WEATHER_POLICY_MANIFEST_SCHEMA_VERSION
        );
        assert_eq!(manifest.payload.admitted_cells, vec![2222]);
        assert_eq!(manifest.payload.candidates[0].replicates, 1);
        assert_eq!(manifest.payload.gates.min_replicates, 1);
        assert_eq!(manifest.payload.gates.min_replicate_samples, 1);
        assert_eq!(
            manifest.payload.env_assignment,
            "GNOSIS_FFN_GUARD_ADMIT_WEATHER_CELLS=2222"
        );
        assert_eq!(
            manifest.signature_algorithm,
            WEATHER_POLICY_SIGNATURE_ALGORITHM
        );
        assert!(manifest.signature.starts_with("fnv1a64:"));
        assert_eq!(manifest.signature.len(), "fnv1a64:".len() + 16);

        let rebuilt = build_weather_policy_manifest(&report).expect("rebuilt manifest");
        assert_eq!(manifest.signature, rebuilt.signature);
    }

