    #[test]
    fn weather_policy_manifest_requires_replicated_cell_evidence() {
        let candidate = WeatherCellPolicyCandidate {
            cell: 3332,
            compared: 32,
            replicates: 1,
            weather_rejects: 2,
            conservative_rejects: 2,
            conservative_rate: 0.0625,
            p50_speedup: 1.10,
            p90_speedup: 1.20,
            ffn_speedup: 1.15,
        };
        let mut report = manifest_report(WeatherProbeSummary::default(), vec![candidate]);
        report.policy_min_replicates = 2;
        report.policy_min_replicate_samples = 4;

        let failure = weather_policy_manifest_failure(&report).expect("replicate gate");
        assert!(failure.contains("cell_3332_replicates=1<2"));

        report.admissible_cell_candidates[0].replicates = 2;
        assert!(weather_policy_manifest_failure(&report).is_none());
        let manifest = build_weather_policy_manifest(&report).expect("manifest");
        assert_eq!(manifest.payload.gates.min_replicates, 2);
        assert_eq!(manifest.payload.gates.min_replicate_samples, 4);
    }

    #[test]
    fn benchmark_gate_splits_semantic_safety_from_speed_claims() {
        let baseline = Summary {
            p50_us: 100,
            p90_us: 140,
            ffn_total_mean_us: 80.0,
            ..Summary::default()
        };
        let slower_candidate = Summary {
            p50_us: 110,
            p90_us: 150,
            ffn_total_mean_us: 90.0,
            divergent_tokens: 0,
            ..Summary::default()
        };
        let divergent_candidate = Summary {
            p50_us: 90,
            p90_us: 130,
            ffn_total_mean_us: 70.0,
            divergent_tokens: 1,
            ..Summary::default()
        };
        let tail_candidate = Summary {
            p50_us: 110,
            p90_us: 130,
            ffn_total_mean_us: 70.0,
            divergent_tokens: 0,
            ..Summary::default()
        };

        assert!(
            benchmark_gate_failure(BenchmarkGate::Semantic, &baseline, &slower_candidate).is_none()
        );
        assert!(
            benchmark_gate_failure(BenchmarkGate::Speedup, &baseline, &slower_candidate)
                .expect("speed gate should fail")
                .contains("p50_not_faster")
        );
        assert!(
            benchmark_gate_failure(BenchmarkGate::TailLatency, &baseline, &tail_candidate)
                .is_none()
        );
        assert!(
            benchmark_gate_failure(BenchmarkGate::Speedup, &baseline, &tail_candidate)
                .expect("speed gate should still require p50")
                .contains("p50_not_faster")
        );
        assert!(
            benchmark_gate_failure(BenchmarkGate::TailLatency, &baseline, &slower_candidate)
                .expect("tail latency gate should still require p90 and FFN")
                .contains("p90_not_faster")
        );
        assert!(
            benchmark_gate_failure(BenchmarkGate::Semantic, &baseline, &divergent_candidate)
                .expect("semantic gate should fail")
                .contains("token_divergence=1")
        );
        assert!(
            benchmark_gate_failure(BenchmarkGate::None, &baseline, &divergent_candidate).is_none()
        );
    }

    #[test]
    fn benchmark_gate_defaults_to_semantic_for_probe_runs() {
        assert_eq!(
            BenchmarkGate::default_for_probe(false),
            BenchmarkGate::Speedup
        );
        assert_eq!(
            BenchmarkGate::default_for_probe(true),
            BenchmarkGate::Semantic
        );
        assert_eq!(
            BenchmarkGate::parse(Some("record".to_string()), true).expect("gate"),
            BenchmarkGate::None
        );
        assert_eq!(
            BenchmarkGate::parse(Some("tail-latency".to_string()), true).expect("gate"),
            BenchmarkGate::TailLatency
        );
        assert!(BenchmarkGate::parse(Some("mystery".to_string()), false).is_err());
    }

    #[test]
    fn weather_grid_starts_parse_explicit_pairs_or_cross_product() {
        assert_eq!(
            weather_grid_starts(Some("8@0, 284@1".to_string()), vec![], vec![], 1, 2)
                .expect("explicit starts"),
            vec![
                WeatherGridStartSpec {
                    token: 8,
                    position: 0
                },
                WeatherGridStartSpec {
                    token: 284,
                    position: 1
                },
            ]
        );

        assert_eq!(
            weather_grid_starts(None, vec![8, 9], vec![0, 2], 1, 1).expect("cross product"),
            vec![
                WeatherGridStartSpec {
                    token: 8,
                    position: 0
                },
                WeatherGridStartSpec {
                    token: 8,
                    position: 2
                },
                WeatherGridStartSpec {
                    token: 9,
                    position: 0
                },
                WeatherGridStartSpec {
                    token: 9,
                    position: 2
                },
            ]
        );

        assert_eq!(
            weather_grid_starts(None, vec![], vec![], 13, 21).expect("default start"),
            vec![WeatherGridStartSpec {
                token: 13,
                position: 21
            }]
        );
        assert!(weather_grid_starts(Some("bad".to_string()), vec![], vec![], 1, 2).is_err());
    }

    #[test]
    fn decode_request_context_names_mode_position_and_request_id() {
        let context = decode_request_context(
            "http://127.0.0.1:8000/decode-next",
            8,
            13,
            21,
            Some("experimental-mirror-tail-low-43-scale-750"),
            Some("3232"),
            Some("3231"),
            Some("3321"),
            Some("8"),
            Some("2.0"),
            Some("4.5"),
            Some("1.25"),
        );

        assert!(context.contains("request_id=bench-decode-next-21"));
        assert!(context.contains("token=8"));
        assert!(context.contains("position=13"));
        assert!(context.contains("mode=experimental-mirror-tail-low-43-scale-750"));
        assert!(context.contains("guard_admit_weather_cells=3232"));
        assert!(context.contains("guard_speculate_weather_cells=3231"));
        assert!(context.contains("guard_deny_weather_cells=3321"));
        assert!(context.contains("predictive_min_gate_up_skip_blocks=8"));
        assert!(context.contains("guard_min_logit_margin=2.0"));
        assert!(context.contains("guard_high_confidence_logit_margin=4.5"));
        assert!(context.contains("guard_rms_delta3_threshold=1.25"));
    }
